#include<bits/stdc++.h>
#define id(x,y,z) ((x)*1600+(y)*40+(z))
using namespace std;
struct edge
{
    long long to,val,nxt;
}e[4000010];
long long head[4000010],tot=1,v[110][110][110];
long long n,m,s,t,d[4000010],now[4000010];
void add1(long long u,long long v,long long w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(long long i=0;i<=t;i++)
    {
        d[i]=0;
    }
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    long long p,q,r,d;
    scanf("%lld%lld%lld%lld",&p,&q,&r,&d);
    s=0;
    t=id(p,q,r)+1;
    for(long long k=1;k<=r;k++)
    {
        for(long long i=1;i<=p;i++)
        {
            for(long long j=1;j<=q;j++)
            {
                scanf("%lld",&v[i][j][k]);
            }
        }
    }
    for(long long i=1;i<=p;i++)
    {
        for(long long j=1;j<=q;j++)
        {
            add(s,id(i,j,1),2e9);
        }
    }
    for(long long k=1;k<r;k++)
    {
        for(long long i=1;i<=p;i++)
        {
            for(long long j=1;j<=q;j++)
            {
                add(id(i,j,k),id(i,j,k+1),v[i][j][k]);
                if(k<=d)
                {
                    continue;
                }
                if(i<p)
                {
                    add(id(i,j,k),id(i+1,j,k-d),2e9);
                }
                if(i>1)
                {
                    add(id(i,j,k),id(i-1,j,k-d),2e9);
                }
                if(j<q)
                {
                    add(id(i,j,k),id(i,j+1,k-d),2e9);
                }
                if(j>1)
                {
                    add(id(i,j,k),id(i,j-1,k-d),2e9);
                }
            }
        }
    }
    for(long long i=1;i<=p;i++)
    {
        for(long long j=1;j<=q;j++)
        {
            add(id(i,j,r),t,v[i][j][r]);
            long long k=r;
            if(k<=d)
            {
                continue;
            }
            if(i<p)
            {
                add(id(i,j,k),id(i+1,j,k-d),2e9);
            }
            if(i>1)
            {
                add(id(i,j,k),id(i-1,j,k-d),2e9);
            }
            if(j<q)
            {
                add(id(i,j,k),id(i,j+1,k-d),2e9);
            }
            if(j>1)
            {
                add(id(i,j,k),id(i,j-1,k-d),2e9);
            }
        }
    }
    printf("%lld",dinic());
    return 0;
}
